        // Item 1 rank: vector=0, bm25=1. Score = 0.5/(60+0+1) + 0.5/(60+1+1)
        // Item 3 rank: vector=2, bm25=0. Score = 0.5/(60+2+1) + 0.5/(60+0+1)

        assert_eq!(results[0].0, "1"); // Item 1 should be first because rank 0 + rank 1 is better than rank 2 + rank 0
        assert_eq!(results[1].0, "3");
        assert_eq!(results[2].0, "2");
    }

fn build_symbol_probes(query: &str, terms: &[String]) -> Vec<String> {
    let mut probes = Vec::new();
    let q = query.trim();
    if !q.is_empty() {
        probes.push(q.to_string());
    }

    let mut ranked_terms: Vec<String> = terms.iter().filter(|t| t.len() >= 3).cloned().collect();
    ranked_terms.sort_by_key(|t| std::cmp::Reverse(t.len()));
    ranked_terms.truncate(4);
    probes.extend(ranked_terms);

    probes.sort();
    probes.dedup();
    probes
}

