    graph: &DiGraph<String, f32>,
    seed_nodes: &[NodeIndex],
    damping: f32,
    tolerance: f32,
    max_iter: usize,
) -> HashMap<NodeIndex, f32> {
    let n = graph.node_count();
    if n == 0 {
        return HashMap::new();
    }

    let mut personalization = vec![0.0; n];
    if !seed_nodes.is_empty() {
        let seed_weight = 1.0 / seed_nodes.len() as f32;
        for &node in seed_nodes {
            if node.index() < n {
                personalization[node.index()] = seed_weight;
            }
        }
    } else {
        let uniform = 1.0 / n as f32;
        personalization.fill(uniform);
    }

    let mut scores = personalization.clone();

    let out_weight_sums: Vec<f32> = graph
        .node_indices()
        .map(|node| graph.edges(node).map(|e| *e.weight()).sum::<f32>())
        .collect();

    let dangling_nodes: Vec<NodeIndex> = graph
        .node_indices()
        .filter(|&node| out_weight_sums[node.index()] == 0.0)
        .collect();

    for _ in 0..max_iter {
        let mut new_scores = vec![0.0; n];

        let dangling_sum: f32 = dangling_nodes
            .iter()
            .map(|&node| scores[node.index()])
            .sum();

        for node in graph.node_indices() {
            let total_out_weight = out_weight_sums[node.index()];
            if total_out_weight > 0.0 {
                for edge in graph.edges(node) {
                    let weight = *edge.weight();
                    let transition_prob = weight / total_out_weight;
                    let contribution = scores[node.index()] * transition_prob * damping;
                    new_scores[edge.target().index()] += contribution;
                }
            }
        }

        for i in 0..n {
            new_scores[i] += damping * dangling_sum * personalization[i];
            new_scores[i] += (1.0 - damping) * personalization[i];
        }

        let diff: f32 = scores
            .iter()
            .zip(new_scores.iter())
            .map(|(a, b)| (a - b).abs())
            .sum();

        scores = new_scores;

        if diff < tolerance {
            break;
        }
    }

    graph
        .node_indices()
        .map(|idx| (idx, scores[idx.index()]))
        .collect()
}","context_path":null,"end_line":110,"exact_score":0.0,"file_path":"/var/folders/mx/tffz_j1d5lg_twyfntz97yr00000gp/T/task-9-code-retrieval-project-52ms9sht/task-9-code-retrieval-fixture/src/graph/ppr.rs","id":"f8fc62e5fd8cd504a34c","language":"rust","lexical_score":0.07500000298023224,"name":null,"ppr_score":0.00900900550186634,"rrf_score":0.011398689821362495,"score":0.011998689733445644,"start_line":31,"vector_score":0.8108912110328674}],"results_compact":[{"file_path":"/var/folders/mx/tffz_j1d5lg_twyfntz97yr00000gp/T/task-9-code-retrieval-project-52ms9sht/task-9-code-retrieval-fixture/src/server/handler.rs","line_range":{"end":642,"start":492},"rank":1,"relevance":{"diagnostics_path":"results[0]","reason":"Matched other chunk by retrieval score","score":0.01527225412428379},"snippet":{"content":"mod tests {
