                "chunk_type": "function",
                "name": "rrf_merge",
                "context_path": "mod:graph",
                "score": 0.91,
                "rrf_score": 0.90,
                "lexical_score": 0.12,
                "exact_score": 0.80,
                "vector_score": 0.75,
                "bm25_score": 11.0,
                "ppr_score": 0.2
            }],
            "count": 1,
            "query": "find rrf merge",
            "contract": { "compatibility": { "clients_must_ignore_unknown_fields": true } },
            "summary": { "result_kind": "collection", "partial": { "is_partial": false } },
